-- Map IRDAI controls to framework
SELECT c.id, f.id, 
  split_part(c.code, '.', 2) || '.' || split_part(c.code, '.', 3) as clause_reference,
  c.title
FROM controls c, frameworks f
WHERE f.code='IRDAI_CSF' AND c.code LIKE 'IRDAI.%'
ON CONFLICT DO NOTHING;

SELECT COUNT(*) as irdai_controls FROM controls WHERE code LIKE 'IRDAI.%';
SELECT COUNT(*) as irdai_mappings FROM control_framework_map cfm JOIN frameworks f ON f.id=cfm.framework_id WHERE f.code='IRDAI_CSF';
