INSERT INTO controls (tenant_id,code,title,description,objective,type,nature,frequency,is_active) VALUES
(NULL,'IRDAI.DE.AE.001','Does the organization have a clearly defined policy including requirements justifying the exceptions, duration of except','Does the organization have a clearly defined policy including requirements justifying the exceptions, duration of exceptions, process of granting exceptions, and authority for approving, authority for review of exceptions granted on a periodic basis by officer(s) preferably at senior levels who are well equipped to understand the business and technical context of the exception(s) ?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.002','Are the security logs maintained and monitored?','Are the security logs maintained and monitored?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.003','Are there any procedure to monitor capacity utilization of critical systems and networks ?','Are there any procedure to monitor capacity utilization of critical systems and networks ?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.004','Are there mechanism to peroidically incorporate lessons learnt to continually improve the response strategies?','Are there mechanism to peroidically incorporate lessons learnt to continually improve the response strategies?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.005','Does the organisation user or system accounts used to perform penetration testing should be controlled and monitored to ','Does the organisation user or system accounts used to perform penetration testing should be controlled and monitored to make sure they are only being used for legitimate purposes, and are removed or restored to normal function after testing is over.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.006','Does the organisation Apply host- based firewalls on end systems','Does the organisation Apply host- based firewalls on end systems','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.007','Does the organisation Apply static and dynamic analysis tools to verify that secure coding practices are being adhered t','Does the organisation Apply static and dynamic analysis tools to verify that secure coding practices are being adhered to for internally developed software.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.008','Does the organisation Associate active ports, services and protocols to the hardware assets assets  (including cloud res','Does the organisation Associate active ports, services and protocols to the hardware assets assets  (including cloud resources) in the asset inventory.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.009','Does the organization disable dormant accounts (preferably automatically) after a set period of inactivity.','Does the organization disable dormant accounts (preferably automatically) after a set period of inactivity.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.010','Does the organisation Automatically lock workstation sessions after a standard period of inactivity.','Does the organisation Automatically lock workstation sessions after a standard period of inactivity.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.011','Does the organisation Block all e- mail attachments entering the organization''s email gateway if the file types are unne','Does the organisation Block all e- mail attachments entering the organization''s email gateway if the file types are unnecessary for the organization''s business.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.012','Does the organisation Conduct regular external and internal penetration tests to identify vulnerabilities and attack vec','Does the organisation Conduct regular external and internal penetration tests to identify vulnerabilities and attack vectors that can be used to exploit enterprise systems successfully.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.013','Does the organisation Configure access for all accounts through as few centralized points of authentication as possible,','Does the organisation Configure access for all accounts through as few centralized points of authentication as possible, including network, security, and cloud systems.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.014','Does the organisation Configure devices to not auto-run content  from removable media.','Does the organisation Configure devices to not auto-run content  from removable media.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.015','Does the organisation Configure monitoring systems to inspect network packets passing through the boundary at each of th','Does the organisation Configure monitoring systems to inspect network packets passing through the boundary at each of the organization''s network boundaries?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.016','Does the organisation Configure network vulnerability scanning tools to detect and alert on unauthorized wireless access','Does the organisation Configure network vulnerability scanning tools to detect and alert on unauthorized wireless access points connected to the wired network.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.017','Does the organisation Configure wireless access on client machines that do have an essential wireless business purpose, ','Does the organisation Configure wireless access on client machines that do have an essential wireless business purpose, to allow access only to authorized wireless networks and to restrict access to other wireless networks.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.018','Does the organisation Create a separate wireless network for personal or untrusted devices. Enterprise access from this ','Does the organisation Create a separate wireless network for personal or untrusted devices. Enterprise access from this network should be treated as untrusted and filtered and audited accordingly.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.019','Does the organization Create a  test bed that mimics a production environment for specific penetration tests and Red Tea','Does the organization Create a  test bed that mimics a production environment for specific penetration tests and Red Team attacks?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.020','Does the organisation Decrypt all encrypted network traffic at the boundary proxy prior to analysing the content. Howeve','Does the organisation Decrypt all encrypted network traffic at the boundary proxy prior to analysing the content. However, the organization may use whitelists of allowed sites that can be accessed through the proxy without decrypting the traffic.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.021','Does the organisation Deliver training to address the skills gap identified to positively impact workforce members'' secu','Does the organisation Deliver training to address the skills gap identified to positively impact workforce members'' security behaviour.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.022','Does the organisation Deny communications with known malicious or unused Internet IP addresses and limit access only','Does the organisation Deny communications with known malicious or unused Internet IP addresses and limit access only','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.023','Does the organisation Deploy Security Information and Event Management (SIEM) or log analytic tool for log correlation a','Does the organisation Deploy Security Information and Event Management (SIEM) or log analytic tool for log correlation and analysis.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.024','Does the organisation Disable workstation to workstation communication to limit an attacker''s ability to move laterally ','Does the organisation Disable workstation to workstation communication to limit an attacker''s ability to move laterally and compromise neighbouring systems, through technologies such as Private VLANs or micro segmentation.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.025','Does the organisation Disable any account that cannot be associated with a business process or business owner.','Does the organisation Disable any account that cannot be associated with a business process or business owner.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.026','Does the organisation Disable wireless access on devices that do not have a business purpose for wireless access.','Does the organisation Disable wireless access on devices that do not have a business purpose for wireless access.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.027','Does the organisation Disable wireless peripheral access of devices (such as Bluetooth and NFC), unless such access is r','Does the organisation Disable wireless peripheral access of devices (such as Bluetooth and NFC), unless such access is required for a business purpose.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.028','Does the organisation Encrypt sensitive information at rest ?','Does the organisation Encrypt sensitive information at rest ?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.029','Does the organisation Encrypt all sensitive information in transit?','Does the organisation Encrypt all sensitive information in transit?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.030','Does the organisation Enforce network-based URL filters that limit a system''s ability to connect to websites not approve','Does the organisation Enforce network-based URL filters that limit a system''s ability to connect to websites not approved by the organization. This filtering shall be enforced for each of the organization''s systems, whether they are physically at an organization''s facilities or not.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.031','Does the organization Ensure that micro segmentation shall be implemented in a network to create separate zones for coun','Does the organization Ensure that micro segmentation shall be implemented in a network to create separate zones for countering lateral movement and','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.032','Whether group companies’ infrastructure, networks, and databases are logically and/or physically segregated, and where a','Whether group companies’ infrastructure, networks, and databases are logically and/or physically segregated, and where a vendor provides services to group companies, whether IT personnel with cross-entity access are segregated, wherever possible?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.033','Does the organisation Ensure that all accounts have an expiration date that is monitored and enforced.','Does the organisation Ensure that all accounts have an expiration date that is monitored and enforced.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.034','Does the organization ensure that all software development personnel receive training in writing secure code for their s','Does the organization ensure that all software development personnel receive training in writing secure code for their specific development environment and responsibilities in case of in- house software development.In case of third party software development, SLAs/Agreements contain clauses on adherence to','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.035','Does the organisation Ensure that appropriate logs are being aggregated to a central log management system for analysis ','Does the organisation Ensure that appropriate logs are being aggregated to a central log management system for analysis and review.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.036','Does the organisation Ensure that only authorized scripting languages are able to run in all web browsers and email clie','Does the organisation Ensure that only authorized scripting languages are able to run in all web browsers and email clients.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.037','Does the organisation Ensure that only fully supported web browsers and email clients are allowed to execute in the orga','Does the organisation Ensure that only fully supported web browsers and email clients are allowed to execute in the organization, ideally only using the latest version i.e., N-1 and above of the browsers and email clients provided by the vendor.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.038','Does the organisation Ensure that the organization''s security awareness program is updated frequently (at least annually','Does the organisation Ensure that the organization''s security awareness program is updated frequently (at least annually) to address new technologies,','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.039','Does the organisation Establish a process to accept and address reports of software vulnerabilities, including providing','Does the organisation Establish a process to accept and address reports of software vulnerabilities, including providing a means for external entities to contact your security group and whether it educates security researchers about CERT-In’s role as a CVE Numbering Authority (CNA), the Responsible Disclosure Framework, and the acknowledgement process administered by CERT-In?.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.040','Does the organisation Establish a program for penetration tests that includes a full scope of blended attacks, such as w','Does the organisation Establish a program for penetration tests that includes a full scope of blended attacks, such as wireless, client- based, and web application (including API)attacks.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.041','Does the organization establish secure coding practices appropriate to the programming language and development environm','Does the organization establish secure coding practices appropriate to the programming language and development environment being used in case of in-house software development and in case of third party software development adherence to securing coding practices as per CERT-IN guidelines should form part of SLAs/Agreements and vendors to demonstrate adherence through independent secure code review reports','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.042','Does the organisation for applications that rely on a database, use standard hardening configuration templates. All syst','Does the organisation for applications that rely on a database, use standard hardening configuration templates. All systems that are part of critical business processes should also be tested.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.043','Does the organisation for all business critical software,enure that explicit error checking is performed and documented ','Does the organisation for all business critical software,enure that explicit error checking is performed and documented for all input, including for size, data type, and acceptable ranges or formats.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.044','Does the organisation If USB storage devices are required, ensure all data stored on such devices must be encrypted whil','Does the organisation If USB storage devices are required, ensure all data stored on such devices must be encrypted while at rest.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.045','Does the organisation Include tests for the presence of unprotected system information and artifacts that would be usefu','Does the organisation Include tests for the presence of unprotected system information and artifacts that would be useful to attackers, including network diagrams, configuration files, older penetration test reports, e- mails or documents containing passwords or other information critical to system operation.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.046','Does the organisation Leverage the Advanced Encryption Standard (AES) to encrypt wireless data in transit.','Does the organisation Leverage the Advanced Encryption Standard (AES) to encrypt wireless data in transit.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.047','Does the organisation Log all URL requests from each of the organization''s systems, whether on-site or a mobile device, ','Does the organisation Log all URL requests from each of the organization''s systems, whether on-site or a mobile device, in order to identify potentially malicious activity and assist incident handlers with identifying potentially compromised systems.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.048','Does the organisation Maintain an inventory of all sensitive information stored, processed, or transmitted by the organi','Does the organisation Maintain an inventory of all sensitive information stored, processed, or transmitted by the organization''s technology systems, including those located on-site or at a remote service provider.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.049','Does the organisation Maintain an inventory of authorized wireless access points connected to the wired network.','Does the organisation Maintain an inventory of authorized wireless access points connected to the wired network.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.050','Does the organisation Maintain an inventory of each of the organization''s authentication systems, including those locate','Does the organisation Maintain an inventory of each of the organization''s authentication systems, including those located on-site or at a remote service provider.','IRDAI CSF Compliance','technical','detective','annual',TRUE)
INSERT INTO controls (tenant_id,code,title,description,objective,type,nature,frequency,is_active) VALUES
(NULL,'IRDAI.DE.CM.051','Does the organisation Maintain separate environments for production and non-production systems. Developers should not ha','Does the organisation Maintain separate environments for production and non-production systems. Developers should not have unmonitored access to production environments.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.052','Does the organization manage all critical/core/perimeter network and network security devices using multi- factor authen','Does the organization manage all critical/core/perimeter network and network security devices using multi- factor authentication and encrypted sessions','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.053','Does the organisation Manage the network infrastructure across network connections that are separated from the business ','Does the organisation Manage the network infrastructure across network connections that are separated from the business use of that network, relying on separate VLANs or, preferably, on entirely different physical connectivity for management sessions for network devices.  For troubleshooting purposes if any remote access is granted to network infrastructure the same should be with necessary prior approvals and for limited period of troubleshooting window','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.054','Does the organisation Monitor attempts to access deactivated accounts through audit logging.','Does the organisation Monitor attempts to access deactivated accounts through audit logging.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.055','Does the organisation On a regular basis, review logs to identify anomalies or abnormal events.','Does the organisation On a regular basis, review logs to identify anomalies or abnormal events.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.056','Does the organisation On a regular basis, tune  SIEM system to better identify actionable events and decrease event nois','Does the organisation On a regular basis, tune  SIEM system to better identify actionable events and decrease event noise.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.057','Does the organisation only use up-to-date and trusted third-party components for the software developed by the organizat','Does the organisation only use up-to-date and trusted third-party components for the software developed by the organization. The Organisations may over a period of time prepare and retain a Software Bill of Material (SBOM) as per CERT-IN guidelines.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.058','Does the organisation perform a skills gap analysis to understand the skills and behaviours workforce members are not ad','Does the organisation perform a skills gap analysis to understand the skills and behaviours workforce members are not adhering to, using this information to build a baseline education roadmap.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.059','Does the organisation perform periodic Red Team exercises to test organizational readiness to identify and stop attacks ','Does the organisation perform periodic Red Team exercises to test organizational readiness to identify and stop attacks or to respond quickly and effectively.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.060','Does the organisation Place application firewalls in front of any critical servers to verify and validate the traffic go','Does the organisation Place application firewalls in front of any critical servers to verify and validate the traffic going to the','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.061','Does the organisation Plan and conduct routine incident, response exercises and scenarios for the workforce involved in ','Does the organisation Plan and conduct routine incident, response exercises and scenarios for the workforce involved in the incident response to maintain awareness and comfort in responding to real world threats. Exercises should test communication channels, decision making, and incident responders technical capabilities using tools and data available to them.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.062','Does the organisation Protect web applications by deploying web application firewalls (WAFs) that inspect all traffic fl','Does the organisation Protect web applications by deploying web application firewalls (WAFs) that inspect all traffic flowing to the web application for common web application attacks. For applications that are not web- based, specific application firewalls should be deployed if such tools are available for the given application type. If the traffic is encrypted, the device should','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.063','Does the organisation Remove sensitive systems not regularly accessed by the organization from the network. These system','Does the organisation Remove sensitive systems not regularly accessed by the organization from the network. These systems shall only be used as stand-alone systems (disconnected from the network) by the business unit needing to occasionally use the system or completely virtualized and powered off until needed.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.064','Does the organisation ensure all remote login access to the organization''s network to encrypt data in transit and use mu','Does the organisation ensure all remote login access to the organization''s network to encrypt data in transit and use multi-factor authentication (MFA).','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.065','Does the organisation ensure multi-factor authentication for all user accounts, on all systems, whether managed on-site ','Does the organisation ensure multi-factor authentication for all user accounts, on all systems, whether managed on-site or by a third-party provider.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.066','Does the organization segment the network to segregate all sensitive information on separated Virtual Local Area Network','Does the organization segment the network to segregate all sensitive information on separated Virtual Local Area Networks (VLANs) for protecting all sensitive information?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.067','Does the organisation Subscribe to URL categorization services to ensure that they are up-to-date with the most recent w','Does the organisation Subscribe to URL categorization services to ensure that they are up-to-date with the most recent website category definitions available. Uncategorized sites shall be blocked by default.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.068','Does the organisation To lower the chance of spoofed or modified emails from valid domains, implement Domain-based Messa','Does the organisation To lower the chance of spoofed or modified emails from valid domains, implement Domain-based Message Authentication, Reporting and Conformance (DMARC) policy and verification, starting by implementing the Sender Policy Framework (SPF) and the Domain Keys Identified Mail(DKIM) standards.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.069','Does the organisation Train the workforce on how to identify different forms of social engineering attacks, such as','Does the organisation Train the workforce on how to identify different forms of social engineering attacks, such as','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.070','Does the organisation Train workforce members on the importance of enabling and utilizing secure authentication.','Does the organisation Train workforce members on the importance of enabling and utilizing secure authentication.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.071','Does the organisation Train workforce members to be aware of causes for unintentional data exposures, such as losing the','Does the organisation Train workforce members to be aware of causes for unintentional data exposures, such as losing their mobile devices or emailing the wrong person due to autocomplete in email.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.072','Does the organisation Train workforce on how to identify and properly store, transfer, archive and destroy sensitive inf','Does the organisation Train workforce on how to identify and properly store, transfer, archive and destroy sensitive information.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.073','Does the organisation Uninstall or disable any unauthorized browser or email client plugins or add-on applications.','Does the organisation Uninstall or disable any unauthorized browser or email client plugins or add-on applications.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.074','Does the organisation Use a wireless intrusion detection system (WIDS) to detect and alert','Does the organisation Use a wireless intrusion detection system (WIDS) to detect and alert','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.075','Does the organisation Use an automated tool, such as host- based Data Loss Prevention, Email DLP  to enforce access cont','Does the organisation Use an automated tool, such as host- based Data Loss Prevention, Email DLP  to enforce access controls to data even when data is copied off a system.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.076','Does the organisation Use DNS filtering services to help block access to known malicious domains.','Does the organisation Use DNS filtering services to help block access to known malicious domains.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.077','Does the organisation Use only standardized and extensively reviewed encryption algorithms.','Does the organisation Use only standardized and extensively reviewed encryption algorithms.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.078','Does the organisation Use sandboxing to analyse and block inbound email attachments with malicious behaviour.','Does the organisation Use sandboxing to analyse and block inbound email attachments with malicious behaviour.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.079','Does the organisation Use vulnerability scanning and penetration testing tools in concert. The results of vulnerability ','Does the organisation Use vulnerability scanning and penetration testing tools in concert. The results of vulnerability scanning assessments should be used as a starting point to guide and focus penetration testing efforts.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.080','Does the organisation Utilize an active discovery tool to identify all sensitive information stored, processed, or trans','Does the organisation Utilize an active discovery tool to identify all sensitive information stored, processed, or transmitted by the organization''s technology systems, including those located on-site or at a remote service provider, and update the organization''s sensitive  information inventory.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.081','Does the organisation Utilize approved whole disk encryption  software to encrypt the hard drive of all mobile devices.','Does the organisation Utilize approved whole disk encryption  software to encrypt the hard drive of all mobile devices.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.082','Does the organisation Verify that the version of all software acquired from outside your organization is still supported','Does the organisation Verify that the version of all software acquired from outside your organization is still supported by the developer or appropriately','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.083','Does the organisation Wherever possible, ensure that Red Team results are documented using open, machine-readable standa','Does the organisation Wherever possible, ensure that Red Team results are documented using open, machine-readable standards (e.g., SCAP). Devise a scoring method for determining the results of Red Team exercises so that results can be compared over time.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.084','Has the organization defined and set a procedure to implement a Security Operations Centre for centralised and coordinat','Has the organization defined and set a procedure to implement a Security Operations Centre for centralised and coordinated monitoring and management of security related incident?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.085','Has the organization defined incidents, method of detection, methods of reporting incidents by employees, vendors and cu','Has the organization defined incidents, method of detection, methods of reporting incidents by employees, vendors and customers and periodicity of monitoring, collection/sharing of threat information, expected response in each scenario/incident type, allocate and communicate clear roles and','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.086','Has the organization implemented measures to control use of VBA/macros in MS office documents, control permissible attac','Has the organization implemented measures to control use of VBA/macros in MS office documents, control permissible attachment types in email systems?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.087','Has the organization implemented mechanism to automatically identify unauthorised device connections to the organization','Has the organization implemented mechanism to automatically identify unauthorised device connections to the organization’s network and block such connections?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.088','Does the organisation conduct periodic tests for all the critical application, server, network devices and data bases?','Does the organisation conduct periodic tests for all the critical application, server, network devices and data bases?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.089','Does the organisation implement a process to communicate vulnerabilities to vendors?','Does the organisation implement a process to communicate vulnerabilities to vendors?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.090','Does the organisation maintain  tracker for closure and corrective action of VAPT?','Does the organisation maintain  tracker for closure and corrective action of VAPT?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.091','Whether a policy to ensure high availability and timely detection of attacks is defined and implemented ?','Whether a policy to ensure high availability and timely detection of attacks is defined and implemented ?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.092','Whether vulnerability assessment and penetration testing procedure and calendar are defined ?','Whether vulnerability assessment and penetration testing procedure and calendar are defined ?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.093','Is VAPT of internet-facing applications or infrastructure components conducted periodically at least once every 6 months','Is VAPT of internet-facing applications or infrastructure components conducted periodically at least once every 6 months by a CERT-In empaneled Auditor','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.094','Does Business applications including APIs or Web Services etc. undergo VAPT Testing including secure code review periodi','Does Business applications including APIs or Web Services etc. undergo VAPT Testing including secure code review periodically & before go live.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.095','Is mandatory security testing conducted for all changes to internet facing information assets','Is mandatory security testing conducted for all changes to internet facing information assets','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.096','Is External Black Grey/White box Penetration Testing (PT) conducted for all internet facing information assets or system','Is External Black Grey/White box Penetration Testing (PT) conducted for all internet facing information assets or systems at least once in a 6months by a CERT-In empaneled Auditor.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.097','Whether, in cases where PT is conducted in a test environment due to unavoidable circumstances, the organization ensures','Whether, in cases where PT is conducted in a test environment due to unavoidable circumstances, the organization ensures that the test environment’s version and configuration resemble the production environment for VAPT, and any deviations are placed before the ISRMC for approval?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.098','Are High risk gaps, reported from the VAPT closed within the time period prescribed under guidelines (one month)followed','Are High risk gaps, reported from the VAPT closed within the time period prescribed under guidelines (one month)followed by mandatory re-validation test.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.099','Are audit gaps reported in VAPT closed within the timeframe provided in the guidelines (two months) followed by mandator','Are audit gaps reported in VAPT closed within the timeframe provided in the guidelines (two months) followed by mandatory re-validation test.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.CM.100','Whether any exception request exceeding 12 months has undergone reassessment and re- approval, and whether all granted e','Whether any exception request exceeding 12 months has undergone reassessment and re- approval, and whether all granted exceptions are formally documented along with the associated risks?','IRDAI CSF Compliance','technical','detective','annual',TRUE)
INSERT INTO controls (tenant_id,code,title,description,objective,type,nature,frequency,is_active) VALUES
(NULL,'IRDAI.DE.CM.101','Is the organizations information assets synchronized with a singular time source? Is there a monitoring process if the d','Is the organizations information assets synchronized with a singular time source? Is there a monitoring process if the devices are not in sync/async with defined time-source ?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.DP.102','Are roles and responsibilities for detection well defined to ensure accountability?','Are roles and responsibilities for detection well defined to ensure accountability?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.DP.103','Do detection activities comply with all applicable requirements?','Do detection activities comply with all applicable requirements?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.DE.DP.104','Has the organization put in place processes/mechanism to identify authorised hardware / mobile devices like Laptops, mob','Has the organization put in place processes/mechanism to identify authorised hardware / mobile devices like Laptops, mobile phones, tablets, etc. and ensure that they are provided connectivity only when they meet the security  requirements prescribed by the organization?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.AM.105','Does the Organisation use client certificates/server to authenticate hardware assets (including cloud resources) connect','Does the Organisation use client certificates/server to authenticate hardware assets (including cloud resources) connecting to the organization''s trusted network?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.AM.106','Does the organisation Utilize port level access control, following 802.1x standards or cloud native equivalents, to cont','Does the organisation Utilize port level access control, following 802.1x standards or cloud native equivalents, to control which devices can authenticate to the network? The authentication system shall be tied into the hardware asset inventory data to ensure only authorized devices can connect to the network.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.AM.107','Does the organization identify critical assets based on their sensitivity?','Does the organization identify critical assets based on their sensitivity?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.AM.108','Does the organization maintain an up-to-date inventory of its hardware, software, information assets, details of network','Does the organization maintain an up-to-date inventory of its hardware, software, information assets, details of network resources and also maintain records of those personnel who are issued such assets?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.AM.109','Has organization maintained an up-to-date centralised inventory of authorised software/applications/libraries, etc. ?','Has organization maintained an up-to-date centralised inventory of authorised software/applications/libraries, etc. ?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.AM.110','Does the organization maintain an up-to-date inventory of its cryptographic assets to ensure preparedness for transition','Does the organization maintain an up-to-date inventory of its cryptographic assets to ensure preparedness for transition to post-quantum cryptographic environments?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.AM.111','Has the organization managed and protected data/information asset considering how the data/information are stored, trans','Has the organization managed and protected data/information asset considering how the data/information are stored, transmitted, processed, accessed and put to use within/outside the organization''s network, and level of risk they are exposed to depending on the sensitivity of the data/information?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.AM.112','Has the organization put in place appropriate environmental controls for securing location of critical assets providing ','Has the organization put in place appropriate environmental controls for securing location of critical assets providing protection from natural threats?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.AM.113','Has the organization put in place mechanism for monitoring any potential compromises or breach to environmental controls','Has the organization put in place mechanism for monitoring any potential compromises or breach to environmental controls?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.AM.114','Is it ensured that unauthorized assets are either removed from the network, quarantined or the inventory is updated in a','Is it ensured that unauthorized assets are either removed from the network, quarantined or the inventory is updated in a timely manner?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.BE.115','Are Priorities for organizational mission, objectives, and activities w.r.t cybersecurity roles, responsibilities, and r','Are Priorities for organizational mission, objectives, and activities w.r.t cybersecurity roles, responsibilities, and risk management decisions established and communicated?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.BE.116','Are Resilience requirements to support delivery of critical services are established for all operating states? (e.g. und','Are Resilience requirements to support delivery of critical services are established for all operating states? (e.g. under duress/attack, during recovery, normal operations)','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.BE.117','Has the organization established Standard Operating Procedures (SOP) for all major IT activities including for connectin','Has the organization established Standard Operating Procedures (SOP) for all major IT activities including for connecting devices  to the network environment of the organization?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.BE.118','Has the organization maintained up-to-date network architecture diagram at the organization level including wired/wirele','Has the organization maintained up-to-date network architecture diagram at the organization level including wired/wireless networks?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.GV.119','Is official designated to assume overall responsibility for governance and monitoring of Information Security?','Is official designated to assume overall responsibility for governance and monitoring of Information Security?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.GV.120','Does the organization form an IS RMC which shall be responsible to ensure that the policy remains updated at all times?','Does the organization form an IS RMC which shall be responsible to ensure that the policy remains updated at all times?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.GV.121','Is the annual audit plan and the reports presented to the Audit Committee of the Board of the organization?','Is the annual audit plan and the reports presented to the Audit Committee of the Board of the organization?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.GV.122','Does Cyber Security Policy include process of recovering from incidents through incident management & other appropriate ','Does Cyber Security Policy include process of recovering from incidents through incident management & other appropriate recovery mechanisms?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.GV.123','Does Cyber Security Policy include process on detecting incidents, anomalies and attacks via appropriate monitoring tool','Does Cyber Security Policy include process on detecting incidents, anomalies and attacks via appropriate monitoring tools/process?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.GV.124','Does Cyber Security Policy include process on protecting assets by deploying suitable controls, tools & measures?','Does Cyber Security Policy include process on protecting assets by deploying suitable controls, tools & measures?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.GV.125','Does Cyber Security Policy include process on responding after identification of the incident, anomaly or attack?','Does Cyber Security Policy include process on responding after identification of the incident, anomaly or attack?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.GV.126','Does the organization implement any operation/process/monetary transactions through API follow best practices from inter','Does the organization implement any operation/process/monetary transactions through API follow best practices from international standards like ISO 27001, COBIT 5, etc? Are the APIs security tested ? Are such practices periodically reviewed?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.GV.127','Are cybersecurity roles and responsibilities coordinated and aligned with internal roles and external partners?','Are cybersecurity roles and responsibilities coordinated and aligned with internal roles and external partners?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.GV.128','Is there a Cyber Crisis Management Plan (CCMP) available? Are Cert-In / NCIIPC guidelines used for preparing Cyber Crisi','Is there a Cyber Crisis Management Plan (CCMP) available? Are Cert-In / NCIIPC guidelines used for preparing Cyber Crisis Management Plan?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.GV.129','Is there a SOC setup available which ensures continuous surveillance ?','Is there a SOC setup available which ensures continuous surveillance ?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.GV.130','Are the reporting procedures being taken to facilitate communication of unusual activities with designated Cyber Securit','Are the reporting procedures being taken to facilitate communication of unusual activities with designated Cyber Security officer ?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.GV.131','Whether a comprehensive Cyber Security Policy is in place ?','Whether a comprehensive Cyber Security Policy is in place ?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.GV.132','Whether a cyber risk management policy is available ?','Whether a cyber risk management policy is available ?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.GV.133','Whether Business Continuity Plan and Disaster Recovery Plan is in place ?','Whether Business Continuity Plan and Disaster Recovery Plan is in place ?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.GV.134','Whether IT architecture including cloud deployement, Saas etc., has been reviewed by the IT Sub Committee of the board ?','Whether IT architecture including cloud deployement, Saas etc., has been reviewed by the IT Sub Committee of the board ?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.GV.135','Whether the Board of the organization formed an  IT Steering Committee (ITSC) and ISRMC  ? Does the committee periodical','Whether the Board of the organization formed an  IT Steering Committee (ITSC) and ISRMC  ? Does the committee periodically review implementation of the Cyber Security policy and IT Policy?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.GV.136','For Cloud and Mobile deployment has the organisation considered   the best practices relating to Cloud, Mobile Security ','For Cloud and Mobile deployment has the organisation considered   the best practices relating to Cloud, Mobile Security and related areas?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.GV.137','Whether, an Independent External Expert (IEE) with substantial IT and/or cybersecurity expertise in managing or guiding ','Whether, an Independent External Expert (IEE) with substantial IT and/or cybersecurity expertise in managing or guiding IT/cybersecurity initiatives or projects  is included as a member of the RMC?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.RA.138','Does the organization identify potential cyber risks (threats and vulnerabilities) along with the likelihood of such thr','Does the organization identify potential cyber risks (threats and vulnerabilities) along with the likelihood of such threats and impact on the business and deploy controls accordingly to suppress the criticality?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.RA.139','Does the organization periodically assess whether all the network devices are configured appropriately to the desired le','Does the organization periodically assess whether all the network devices are configured appropriately to the desired level of network security?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.RA.140','Are risk responses identified and prioritized?','Are risk responses identified and prioritized?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.RA.141','Are threats from both internal and external parties identified and documented?','Are threats from both internal and external parties identified and documented?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.RM.142','Are Risk management processes established, managed, and agreed to by organizational stakeholders?','Are Risk management processes established, managed, and agreed to by organizational stakeholders?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.RM.143','Is Organizational risk tolerance is determined and clearly expressed?','Is Organizational risk tolerance is determined and clearly expressed?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.SC.144','Does vendors adhere to the applicable guidelines provided in the Cyber Security policy? Does the organization obtains th','Does vendors adhere to the applicable guidelines provided in the Cyber Security policy? Does the organization obtains the necessary self-certifications from them to ensure compliance with','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.SC.145','Has the vendors implemented appropriate information security controls and cybersecurity framework?','Has the vendors implemented appropriate information security controls and cybersecurity framework?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.SC.146','Are Vendors agreement documents  maintained and updated ?','Are Vendors agreement documents  maintained and updated ?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.SC.147','Are there process for monitoring third - party access to protected or sensitive information?','Are there process for monitoring third - party access to protected or sensitive information?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.SC.148','Whether the Regulated Entity, through SLAs, requires service providers / outsourced entities to obtain prior written per','Whether the Regulated Entity, through SLAs, requires service providers / outsourced entities to obtain prior written permission before any further outsourcing','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.SC.149','Is the Cloud Service Provider (CSP) MeitY empaneled CSP and holds a valid STQC (or any other equivalent agency appointed','Is the Cloud Service Provider (CSP) MeitY empaneled CSP and holds a valid STQC (or any other equivalent agency appointed by','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.ID.SC.150','Has the organization signed NDA with CSP covering all aspects relating to privacy, confidentiality, security and busines','Has the organization signed NDA with CSP covering all aspects relating to privacy, confidentiality, security and business continuity?','IRDAI CSF Compliance','technical','detective','annual',TRUE)
INSERT INTO controls (tenant_id,code,title,description,objective,type,nature,frequency,is_active) VALUES
(NULL,'IRDAI.ID.SC.151','Does the organization contractually require that the cloud service provider will completely eliminate any trace of data/','Does the organization contractually require that the cloud service provider will completely eliminate any trace of data/ information in disks, backups, etc., at the termination of the contract?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.AC.152','Are ICT infrastructure logs maintained for a rolling period of 180 days as per CERT-In directions?','Are ICT infrastructure logs maintained for a rolling period of 180 days as per CERT-In directions?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.AC.153','Are ICT infrastructure logs, Critical and Business data stored in India?','Are ICT infrastructure logs, Critical and Business data stored in India?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.AC.154','Are third-party staff who are given access to the organization''s critical systems, networks, and other computer resource','Are third-party staff who are given access to the organization''s critical systems, networks, and other computer resources subjected to strict supervision, monitoring, and access restrictions?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.AC.155','Do all critical systems of the organization that is accessible over the internet have two-factor security (Such as VPNs,','Do all critical systems of the organization that is accessible over the internet have two-factor security (Such as VPNs, Firewall Controls, etc.)?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.AC.156','Does the access control policy address strong password management control for access to systems, applications, networks ','Does the access control policy address strong password management control for access to systems, applications, networks and databases?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.AC.157','Does the organization proactively deactivate access of privileges of users who are leaving the organization or whose acc','Does the organization proactively deactivate access of privileges of users who are leaving the organization or whose access privileges have been withdrawn?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.AC.158','Has the organization deployed security measures and controls to supervise staff with elevated access entitlements (Such ','Has the organization deployed security measures and controls to supervise staff with elevated access entitlements (Such as privileged users) to organization''s critical systems? Has the organization also restricted the no. of privileged user to the least number and deployed periodic review mechanism/process against privileged users'' activities? Are such privileged users restricted of access to system logs where their activities are being captured?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.AC.159','Has the organization ensured that no personnel in the company have natural rights to access confidential data, applicati','Has the organization ensured that no personnel in the company have natural rights to access confidential data, applications,  system resources or facilities by virtue of rank or position?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.AC.160','Has the organization ensured that the perimeter of the critical equipment’s room/area are physically secured and continu','Has the organization ensured that the perimeter of the critical equipment’s room/area are physically secured and continuously monitored by employing physical, human, and procedural controls such as security guards, CCTVs, Card','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.AC.161','Has the organization formulated an internet access policy to monitor and regulate the use of internet & internet based s','Has the organization formulated an internet access policy to monitor and regulate the use of internet & internet based services such as social media sites, cloud- based storage sites, etc. within the organization''s critical IT infrastructure?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.AC.162','Has the organization implemented access to IT systems, applications, databases and networks on a need-to-use basis and t','Has the organization implemented access to IT systems, applications, databases and networks on a need-to-use basis and the principle of least privilege? Is the access granted using strong authentication mechanisms and only when it is required ?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.AC.163','Has the organization implemented controls for providing identification and authentication of customers for access to par','Has the organization implemented controls for providing identification and authentication of customers for access to partner systems using secure authentication technologies?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.AC.164','Has the organization implemented controls to minimize invalid login  counts, deactivate dormant accounts?','Has the organization implemented controls to minimize invalid login  counts, deactivate dormant accounts?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.AC.165','Is physical access to the critical systems of the organization restricted to the minimum number of authorized officials?','Is physical access to the critical systems of the organization restricted to the minimum number of authorized officials? Are third party staffs strictly monitored and physically accompanied all the time by the authorized employee of the organization while third party staff has been given physical access to critical systems ?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.AC.166','Is physical access to the critical systems of the organization revoked immediately if the same is no longer required?','Is physical access to the critical systems of the organization revoked immediately if the same is no longer required?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.AT.167','Are the history and versions of training content maintained?','Are the history and versions of training content maintained?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.AT.168','Are the targeted awareness/training for key personnel conducted periodically?','Are the targeted awareness/training for key personnel conducted periodically?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.AT.169','Are the training programs reviewed and updated periodically?','Are the training programs reviewed and updated periodically?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.AT.170','Are security policy/ies covering secure and acceptable use of network/assets including customer information/data defined','Are security policy/ies covering secure and acceptable use of network/assets including customer information/data defined and communicated to users/employees, vendors & partners , and also educating them about cybersecurity risks and protection measures at their level.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.AT.171','Do users indicate that they understand their responsibilities?','Do users indicate that they understand their responsibilities?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.AT.172','Is awareness level evaluated periodically?','Is awareness level evaluated periodically?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.AT.173','Is there additional training for leaders to understand their roles   in the event of a security incident?','Is there additional training for leaders to understand their roles   in the event of a security incident?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.AT.174','Is there a process to handle  if a user does not complete the training?','Is there a process to handle  if a user does not complete the training?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.AT.175','Is someone responsible for creating the security training for the organization?','Is someone responsible for creating the security training for the organization?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.AT.176','Has the Organization periodically participated in national/ sectoral/ organisational Cyber Security Exercises?','Has the Organization periodically participated in national/ sectoral/ organisational Cyber Security Exercises?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.DS.177','Are open ports on network and systems which are not in use blocked ?','Are open ports on network and systems which are not in use blocked ?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.DS.178','Does the application be set to automatically log a user off the application after a predefined period of inactivity?','Does the application be set to automatically log a user off the application after a predefined period of inactivity?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.DS.179','Does the application force password expiration and prevent users from reusing a password?','Does the application force password expiration and prevent users from reusing a password?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.DS.180','Does the system administrator enforce password policy and/or complexity such as minimum length, numbers and alphabet req','Does the system administrator enforce password policy and/or complexity such as minimum length, numbers and alphabet requirements, and upper and lower case constraint, etc.?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.DS.181','Does the application force “new” users to change their password upon first login into the application?','Does the application force “new” users to change their password upon first login into the application?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.DS.182','Does the application prohibit users from logging into the application on more than one workstation at the same time with','Does the application prohibit users from logging into the application on more than one workstation at the same time with the same user ID?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.DS.183','Does the application support  integration with the enterprise identity management system?','Does the application support  integration with the enterprise identity management system?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.DS.184','Does the organization authorize data storage devices within their IT infrastructure through appropriate validation proce','Does the organization authorize data storage devices within their IT infrastructure through appropriate validation process?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.DS.185','Is there a process by which the organization maintains the evidence of media disposal?','Is there a process by which the organization maintains the evidence of media disposal?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.DS.186','Has there been a implementation of a data-disposal and data- retention policy?','Has there been a implementation of a data-disposal and data- retention policy?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.DS.187','Are there processes for media formatting?','Are there processes for media formatting?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.DS.188','Is there measurement a client system''s vulnerabilities?','Is there measurement a client system''s vulnerabilities?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.DS.189','Are appropriate and effective security measures in place to share the data with third Parties ?','Are appropriate and effective security measures in place to share the data with third Parties ?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.DS.190','Are appropriate technologies implemented for data mobility security?','Are appropriate technologies implemented for data mobility security?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.IP.191','Does the organisation maintain back-up of source code respository for critical applications developed in-house and for t','Does the organisation maintain back-up of source code respository for critical applications developed in-house and for third party softwares considered business critical entered into an escrow arrangement?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.IP.192','Are Physically or logically segregated systems used to isolate and run software that is  required for business operation','Are Physically or logically segregated systems used to isolate and run software that is  required for business operations but incur higher risk for the organization.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.IP.193','Are the contents of the Web site backed-up to ensure an orderly recovery if the site is corrupted?','Are the contents of the Web site backed-up to ensure an orderly recovery if the site is corrupted?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.IP.194','Are there methods to prevent unauthorized access by other groups into individual files and department-shared files?','Are there methods to prevent unauthorized access by other groups into individual files and department-shared files?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.IP.195','Are there procedures for limiting access to LAN and network operating software?','Are there procedures for limiting access to LAN and network operating software?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.IP.196','Are updates/changes to the Website independently reviewed, approved and tested?','Are updates/changes to the Website independently reviewed, approved and tested?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.IP.197','Does information security policy cover use of devices such as mobile phones, faxes, photocopiers, scanners, etc., within','Does information security policy cover use of devices such as mobile phones, faxes, photocopiers, scanners, etc., within their critical IT infrastructure, that can be used  for capturing and transmission of sensitive data?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.IP.198','Does the organisation utilize application whitelisting technology on all assets to ensure that only authorized software ','Does the organisation utilize application whitelisting technology on all assets to ensure that only authorized software executes and all unauthorized software is blocked from executing on assets?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.IP.199','Does the organisation utilize software inventory tools throughout the organization to automate the documentation of all ','Does the organisation utilize software inventory tools throughout the organization to automate the documentation of all software on business systems.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.PR.IP.200','Does the organization have a documented disaster recovery plan for processing critical jobs in the event of a major hard','Does the organization have a documented disaster recovery plan for processing critical jobs in the event of a major hardware or software failure?','IRDAI CSF Compliance','technical','detective','annual',TRUE)
INSERT INTO controls (tenant_id,code,title,description,objective,type,nature,frequency,is_active) VALUES
