(NULL,'IRDAI.RS.IM.239','Are Response strategies updated periodically?','Are Response strategies updated periodically?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.RS.IM.240','Are the Board members provided with training programmes on IT Risk / Cybersecurity Risk and evolving best practices in t','Are the Board members provided with training programmes on IT Risk / Cybersecurity Risk and evolving best practices in this regard so as to cover all the Board members at least once a year.','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.RS.IM.241','Are top management sensitised on various technological developments and cyber security related developments periodically','Are top management sensitised on various technological developments and cyber security related developments periodically?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
