(NULL,'IRDAI.WFRL.284','Are activities like walkthrough and interviews performed using approved remote access software over secure and hardened ','Are activities like walkthrough and interviews performed using approved remote access software over secure and hardened systems of auditee and auditor organizations?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.WFRL.285','Are evidences and artefacts classified, securely demonstrated to concerned stakeholders and not shared out of authorized','Are evidences and artefacts classified, securely demonstrated to concerned stakeholders and not shared out of authorized domains?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
