(NULL,'IRDAI.WFRL.287','Are plans and procedures set in place by the organization for Cybersecurity incident response and Crisis management acti','Are plans and procedures set in place by the organization for Cybersecurity incident response and Crisis management activities?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.WFRL.288','Is Cyber Security Project management performed remotely?','Is Cyber Security Project management performed remotely?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
(NULL,'IRDAI.WFRL.289','Confirm whether there are hardening procedures to check / scan systems brought back to Office?','Confirm whether there are hardening procedures to check / scan systems brought back to Office?','IRDAI CSF Compliance','technical','detective','annual',TRUE),
